func constructLayoutPath(typ, layout, variations, extension string) string {

	if extension == "" && (layout == "" || variations == "") {
		return ""
	}

	var (
		p	strings.Builder
		needDot	bool
	)

	if typ != "" {
		p.WriteString(typ)
		p.WriteString("/")
	}

	if layout != "" {
		p.WriteString(layout)
		needDot = true
	}

	if variations != "" {
		if needDot {
			p.WriteString(".")
		}
		p.WriteString(variations)
		needDot = true
	}

	if extension != "" {
		if needDot {
			p.WriteString(".")
		}
		p.WriteString(extension)
	}

	return p.String()
}
